import requests

def main():
    base_url = "http://10.0.162.112:80"
    paths = [
        "/js/login.js"
    ]

    session = requests.Session()

    for path in paths:
        url = base_url + path
        try:
            response = session.get(url, timeout=10)
            response.raise_
